// Fuzzy match: find city ID by name
export function findCityId(name: string): string | null {
  if (!name) return null
  const normalized = name.trim().toLowerCase()
  for (const [city, id] of Object.entries(AMEEX_CITIES)) {
    if (city.toLowerCase() === normalized) return id
  }
  // partial match
  for (const [city, id] of Object.entries(AMEEX_CITIES)) {
    if (city.toLowerCase().includes(normalized) || normalized.includes(city.toLowerCase())) return id
  }
  return null
}
